from flask import Flask, request, jsonify
import redis
import os
import json
from dotenv import load_dotenv

load_dotenv()

app = Flask(__name__)

# Redis connection settings
REDIS_NODES = os.getenv("REDIS_NODES").split(',')
REDIS_PASSWORD = os.getenv("REDIS_PASSWORD")

# Create Redis connections
redis_clients = [redis.StrictRedis(host=node, port=6379, password=REDIS_PASSWORD, decode_responses=True) for node in REDIS_NODES]

def get_redis_client():
    # Simple round-robin load balancing
    return redis_clients[0]  # Modify for more complex load balancing

@app.route('/store', methods=['POST'])
def store_data():
    data = request.json
    key = data.get('key')
    value = data.get('value')
    ttl = data.get('ttl', 3600)  # Default TTL of 1 hour

    if not key or not value:
        return jsonify({"error": "Key and value are required"}), 400

    client = get_redis_client()
    client.setex(key, ttl, json.dumps(value))
    return jsonify({"message": "Data stored successfully"}), 201

@app.route('/retrieve/<key>', methods=['GET'])
def retrieve_data(key):
    client = get_redis_client()
    value = client.get(key)

    if value is None:
        return jsonify({"error": "Key not found"}), 404

    return jsonify({"key": key, "value": json.loads(value)}), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)